import Base from '@/lib/core';
import { UIEvents } from '@/lib/events/event-catalog.js';

/**
 * ============================================================
 *
 * # 模块：ClearScoreAnimation 消除得分动画
 *
 * ============================================================
 *
 * 在消除行位置显示上浮渐隐的得分数字。
 *
 * ## 动画表现
 *
 * - 得分数字从消除行位置持续上浮
 * - 透明度从 1 逐渐衰减到 0，营造淡出效果
 * - 不阻塞用户输入，纯粹视觉反馈
 *
 * ## 时间驱动
 *
 * - 状态更新：每 16ms 固定步长更新透明度和上浮偏移
 * - 动画结束：alpha <= 0 时设置 _finished = true
 *
 * ## 生命周期
 *
 * 1. Constructor → 记录得分数据，启动定时器
 * 2. Scheduler 每 16ms 更新状态
 * 3. Alpha <= 0 → 设置 _finished = true
 * 4. Dispose() → 取消定时器
 *
 * @augments Base
 * @class ClearScoreAnimation
 */
class ClearScoreAnimation extends Base {
  /**
   * ## 构造函数
   *
   * @param {object} options - 配置对象
   */
  constructor(options) {
    super(options);
    this.initialize();
  }

  /**
   * ## initialize：初始化动画
   *
   * 设置动画属性和初始状态，启动状态更新定时器。
   *
   * @returns {void}
   */
  initialize() {
    const { scoreData, Scheduler } = this;
    const { score, lines, combo, comboScore } = scoreData;

    /**
     * 渲染层级（300，在消行闪烁层之上）。
     *
     * @type {number}
     */
    this.layer = 300;

    /**
     * 是否阻塞用户输入。
     *
     * @type {boolean}
     */
    this.blocking = false;

    /**
     * 动画名称标识。
     *
     * @type {string}
     */
    this.name = 'clear-score';

    /**
     * 是否已结束。
     *
     * @type {boolean}
     */
    this._finished = false;

    /**
     * 动画状态。
     *
     * | 属性       | 类型   | 说明                     |
     * | :--------- | :----- | :----------------------- |
     * | score      | number | 本次消除得分             |
     * | combo      | number | 当前连击次数             |
     * | comboScore | number | 本次连击额外加分         |
     * | y          | number | 消除行号                 |
     * | alpha      | number | 当前透明度（1 → 0 渐隐） |
     * | offsetY    | number | Y 轴上浮偏移量           |
     *
     * @type {object}
     */
    this.state = {
      score,
      combo: combo || 0,
      comboScore: comboScore || 0,
      y: lines[lines.length - 1],
      alpha: 1,
      offsetY: 0,
    };

    /**
     * 状态更新定时器 ID。
     *
     * @type {number}
     */
    this._updateId = Scheduler.interval(() => {
      this._update();
    }, 16);
  }

  /**
   * ## _update：更新动画状态
   *
   * 每 16ms 调用一次，以固定步长更新透明度和上浮偏移。
   *
   * @returns {void}
   */
  _update() {
    this.state.alpha -= 0.0196;
    this.state.offsetY += 0.34;

    if (this.state.alpha <= 0) {
      this._finished = true;
    }
  }

  /**
   * ## dispose：清理资源
   *
   * 取消状态更新定时器。
   *
   * @returns {void}
   */
  dispose() {
    const { Scheduler } = this;
    Scheduler.cancel(this._updateId);
  }

  /**
   * ## render：渲染动画
   *
   * 将当前状态传递给 UI 层绘制上浮渐隐的得分数字。
   *
   * @returns {void}
   */
  render() {
    const { state, Game } = this;
    const events = UIEvents(Game.id);
    this.emit(events.RENDER_CLEAR_SCORE, { state: { ...state } });
  }
}

export default ClearScoreAnimation;
