import setBeginningState from '@/lib/game/actions/set-beginning-state.js';
import {
  AudioEvents,
  AIEvents,
  AnimationsEvents,
  CommandEvents,
  ReplayEvents,
  UIEvents,
  GameEvents,
} from '@/lib/events/event-catalog.js';

/**
 * ============================================================
 *
 * # 重置游戏状态
 *
 * ============================================================
 *
 * 将游戏从当前状态安全地重置回主菜单或重新开始游戏。
 *
 * ## 使用场景
 *
 * | mode      | 说明                                    |
 * | :-------- | :-------------------------------------- |
 * | main-menu | Game Over 后返回主菜单，难度重置为 easy |
 * | playing   | 游戏中强制重新开始，保留当前等级和难度  |
 *
 * ## 执行流程
 *
 * | 步骤 | 操作           | 说明                          |
 * | :--- | :------------- | :---------------------------- |
 * | 1    | 停止背景音乐   | 避免状态切换时音频继续播放    |
 * | 2    | 清除动画和命令 | 确保无残留的动画/输入状态     |
 * | 3    | 重置棋盘数据   | 清空棋盘为初始状态            |
 * | 4    | 重置难度和等级 | 返回主菜单时难度→easy，等级→1 |
 * | 5    | 设置初始状态   | 分数归零、行数归零等          |
 * | 6    | 更新 UI 显示   | 刷新 HUD 和模式显示           |
 * | 7    | 停止 AI        | 切换回人类控制                |
 * | 8    | 重置控制器     | 控制器设为 human              |
 * | 9    | 重置回放       | 清除录制/回放数据             |
 *
 * ## 调用时机
 *
 * - Game Over 后返回主菜单
 * - 游戏中按 R 键强制重新开始
 * - 回放结束后返回主菜单
 *
 * @function reset
 * @param {object} runtime - 游戏运行时对象
 * @param {string} [mode='main-menu'] - 重置的目标模式. Default is `'main-menu'`
 * @returns {void}
 */
const reset = (runtime, mode = 'main-menu') => {
  const { id, Store } = runtime;
  const AUE = AudioEvents();
  const AIE = AIEvents(id);
  const ANE = AnimationsEvents(id);
  const CE = CommandEvents(id);
  const RE = ReplayEvents(id);
  const GE = GameEvents(id);
  const UE = UIEvents(id);
  const difficulty =
    runtime.isVersus() && Store.getMode() !== 'battle-over'
      ? Store.getDifficulty()
      : 'easy';

  let level = Store.getLevel();

  // 步骤 1：停止背景音乐
  runtime.emit(AUE.STOP_BGM);

  // 步骤 2：清除动画和命令队列
  runtime.emit(ANE.CLEAR);
  runtime.emit(CE.CLEAR);

  // 步骤 3：重置棋盘数据
  Store.resetBoard();

  // 步骤 4：重置难度和等级
  if (mode === 'main-menu') {
    Store.setDifficulty(difficulty);
    level = 1;
    runtime.emit(AUE.PLAY_SOUND, { sound: 'SWITCH_SCENE' });
  }

  // 步骤 5：设置游戏初始状态
  setBeginningState(runtime, mode, level);

  // 步骤 6：更新 UI 显示
  runtime.emit(UE.UPDATE_HUD, { state: Store.getState() });
  runtime.emit(UE.UPDATE_MODE, { mode });
  runtime.emit(GE.RESET_TIMER);
  runtime.emit(UE.CLEAR_NEXT_PIECE);
  runtime.emit(UE.CLEAR_HOLD_PIECE);

  // 步骤 7：停止 AI
  runtime.emit(AIE.STOP);

  // 步骤 8：重置控制器
  const controller = runtime.isVersus() ? Store.getController() : 'human';
  Store.setController(controller);
  runtime.emit(UE.UPDATE_CONTROLLER, { controller });

  // 步骤 9：重置回放
  runtime.emit(RE.RESET);

  // 步骤 10：重启 AI
  if (controller === 'ai') {
    runtime.emit(AIE.START);
  }
};

export default reset;
